def letterCombinations(digits: str) -> list[str]:
    if not digits:
        return []

    phone_map = {
        '2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl',
        '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'
    }

    combinations = [""]

    for digit in digits:
        if digit not in phone_map:
            # Geçersiz bir rakam (örneğin '0' veya '1') gelirse atla veya hata fırlat
            # Bu problem genellikle 2-9 arası rakamlar bekler.
            continue

        current_letters = phone_map[digit]
        new_combinations = []

        for combo_so_far in combinations:
            for letter in current_letters:
                new_combinations.append(combo_so_far + letter)

        combinations = new_combinations

    return combinations

if __name__ == '__main__':
    # Örnek kullanım:
    print(letterCombinations("23"))
    # Çıktı: ['ad', 'ae', 'af', 'bd', 'be', 'bf', 'cd', 'ce', 'cf']

    print(letterCombinations(""))
    # Çıktı: []

    print(letterCombinations("2"))
    # Çıktı: ['a', 'b', 'c']

    print(letterCombinations("79"))
